 assign Cout = obf_g[3] | (obf_g[2] & p[3]) | (obf_g[1] & p[2] & p[3]) | (obf_g[0] & p[1] & p[2] & p[3]) | (Cin & p[0] & p[1] & p[2] & p[3]); 
